func Test_StaticFileServerReturnsTextFile(t *testing.T) {
	// Tests serving a plain text file with Cache-Control headers.
	baseURL := os.Getenv("MOCK_SERVER_URL")
	if baseURL == "" {
		baseURL = "http://localhost:8080"
	}
	body := strings.NewReader("")
	req, err := http.NewRequest("GET", baseURL+"/fixtures/static_file_server_returns_text_file", body)
	if err != nil {
		t.Fatalf("new request failed: %v", err)
	}
	noRedirectClient := &http.Client{
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}
	resp, err := noRedirectClient.Do(req)
	if err != nil {
		t.Fatalf("request failed: %v", err)
	}
	defer resp.Body.Close()
	bodyBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		t.Fatalf("read body failed: %v", err)
	}
	if resp.StatusCode != 200 {
		t.Fatalf("status: got %d want 200", resp.StatusCode)
	}
	want := `Hello from static storage`
	if strings.TrimSpace(string(bodyBytes)) != want {
		t.Fatalf("body: got %q want %q", string(bodyBytes), want)
	}
	if !strings.Contains(resp.Header.Get(`cache-control`), `public, max-age=60`) {
		t.Fatalf("header %s mismatch: got %q want to contain %q", `cache-control`, resp.Header.Get(`cache-control`), `public, max-age=60`)
	}
	if !strings.Contains(resp.Header.Get(`content-type`), `text/plain`) {
		t.Fatalf("header %s mismatch: got %q want to contain %q", `content-type`, resp.Header.Get(`content-type`), `text/plain`)
	}
}

